import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by escaping it before printing to the HTML output
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");
        out.println("User Input: " + Encode.forHtml(userInput));  // Escaping user input to prevent XSS
        out.println("</body>");
        out.println("</html>");

        // Closing the PrintWriter
        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
